import{_ as a,c as e,o as t,V as r}from"./chunks/framework.Y2m55Jsw.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"python/112全國技藝競賽筆記/02-資料結構/雜湊表HashTable.md","filePath":"python/112全國技藝競賽筆記/02-資料結構/雜湊表HashTable.md","lastUpdated":1718541094000}'),s={name:"python/112全國技藝競賽筆記/02-資料結構/雜湊表HashTable.md"},l=r('<h2 id="雜湊表-hash-table" tabindex="-1">雜湊表(Hash Table) <a class="header-anchor" href="#雜湊表-hash-table" aria-label="Permalink to &quot;雜湊表(Hash Table)&quot;">​</a></h2><ul><li><a href="https://zh.wikipedia.org/zh-tw/%E5%93%88%E5%B8%8C%E8%A1%A8" target="_blank" rel="noreferrer">雜湊表-wiki</a></li><li><a href="https://ithelp.ithome.com.tw/articles/10268077" target="_blank" rel="noreferrer">【Day9】[資料結構]-雜湊表Hash Table</a></li></ul><p>雜湊表（Hash table，也叫哈希表），是根據鍵（Key）而直接查詢在記憶體儲存位置的資料結構。也就是說，它通過計算出一個鍵值的函數，將所需查詢的數據映射到表中一個位置來讓人查詢，這加快了查找速度。這個映射函數稱做雜湊函數，存放記錄的數組稱做雜湊表</p><p>這種方法使得查找、插入和刪除等操作可以在平均時間複雜度為</p><p>O(1)</p><p>的情況下完成，這也是雜湊表作為資料結構非常重要的一個原因。然而，當出現雜湊衝突時，即兩個不同的鍵映射到了同一個儲存位置，雜湊表的操作效率可能會下降。因此，設計一個好的<strong>雜湊函數以減少雜湊衝突</strong>是使用雜湊表時需要考慮的一個重要因素。</p>',6),o=[l];function h(_,n,i,p,c,d){return t(),e("div",null,o)}const T=a(s,[["render",h]]);export{f as __pageData,T as default};
